import { apiRequest } from '../../support/helpers/apiClient';
import { test, expect } from '../../support/fixtures/routeShyftStory26.fixture';

function detailPath(resourceCollection: string, requestId: string): string {
  return resourceCollection + '/' + requestId;
}

test.describe('Story 2-6 Canonical Timezone Processing Across Intake and Scheduling (ATDD API RED)', () => {
  test.skip('[P0] persists UTC at rest while returning localized display timestamps using user->tenant->system fallback @P0', async ({ request, story26Context, story26Headers, story26HappyPayload }) => {
    const response = await apiRequest(request, {
      method: 'POST',
      path: story26Context.paths.resourceCollection,
      headers: story26Headers,
      data: story26HappyPayload,
    });

    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body).toMatchObject({
      ok: true,
      code: story26Context.successCode,
      data: {
        requestId: expect.any(String),
        status: story26Context.statusLabel,
      },
    });
  });

  test.skip('[P0] refuses invalid timezone resolution inputs with deterministic refusal details @P0', async ({ request, story26Context, story26Headers, story26RefusalPayload }) => {
    const response = await apiRequest(request, {
      method: 'POST',
      path: story26Context.paths.resourceCollection,
      headers: story26Headers,
      data: story26RefusalPayload,
    });

    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body).toMatchObject({
      ok: false,
      refusalType: 'business',
      code: story26Context.refusalCode,
      data: {
        alternatives: expect.any(Array),
        timezoneSource: expect.anything(),
      },
    });
  });

  test.skip('[P0] applies deterministic fallback source metadata when user preference is unavailable @P0', async ({ request, story26Context, story26Headers, story26HappyPayload }) => {
    const createResponse = await apiRequest(request, {
      method: 'POST',
      path: story26Context.paths.resourceCollection,
      headers: story26Headers,
      data: story26HappyPayload,
    });
    const createBody = await createResponse.json();
    const requestId = createBody?.data?.requestId ?? story26Context.requestId;

    const response = await apiRequest(request, {
      method: 'GET',
      path: detailPath(story26Context.paths.resourceCollection, requestId),
      headers: story26Headers,
    });

    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body).toMatchObject({
      ok: true,
      code: story26Context.linkageCode,
      data: {
        requestId,
        commitmentId: expect.any(String),
      },
    });
  });

  test.skip('[P1] suppresses raw UTC display fields in operational API contracts @P1', async ({ request, story26Context, story26Headers, story26RefusalPayload }) => {
    const response = await apiRequest(request, {
      method: 'POST',
      path: story26Context.paths.resourceCollection,
      headers: story26Headers,
      data: story26RefusalPayload,
    });

    expect(response.status()).toBe(200);
    const body = await response.json();
    expect(body).toMatchObject({
      ok: false,
      code: story26Context.refusalCode,
      data: {
        timezoneSource: expect.anything(),
      },
    });
  });

  test.skip('[P1] keeps envelope keys stable across localization success and timezone-refusal outcomes @P1', async ({ request, story26Context, story26Headers, story26HappyPayload, story26RefusalPayload }) => {
    const successResponse = await apiRequest(request, {
      method: 'POST',
      path: story26Context.paths.resourceCollection,
      headers: story26Headers,
      data: story26HappyPayload,
    });
    const refusalResponse = await apiRequest(request, {
      method: 'POST',
      path: story26Context.paths.resourceCollection,
      headers: story26Headers,
      data: story26RefusalPayload,
    });

    expect(successResponse.status()).toBe(200);
    expect(refusalResponse.status()).toBe(200);

    const successBody = await successResponse.json();
    const refusalBody = await refusalResponse.json();
    const requiredKeys = ['ok', 'code', 'message', 'correlationId', 'tenantId'];

    expect(requiredKeys.every((key) => Object.prototype.hasOwnProperty.call(successBody, key))).toBe(true);
    expect(requiredKeys.every((key) => Object.prototype.hasOwnProperty.call(refusalBody, key))).toBe(true);
  });
});
